    for p in self.providers:
        try:
            client = self.clients[p.name]
            stream = client.chat.completions.create(
                model=p.model, messages=messages, stream=True, **kwargs,
            )
            for chunk in stream:
                if delta := chunk.choices[0].delta.content:
                    yield delta
            return
        except Exception as e:
