"""Agentic RAG: LangGraph plan -> retrieve -> grade -> answer/loop."""
from __future__ import annotations

import os
from typing import TypedDict, Annotated
import operator

from langchain_anthropic import ChatAnthropic
from langchain_qdrant import QdrantVectorStore
from langgraph.graph import StateGraph, END
from pydantic import BaseModel, Field

from rag_qdrant_basic import BGEEmbeddings  # reuse from basic-rag-langchain-qdrant


class GraphState(TypedDict):
    question: str
    sub_questions: list[str]
    retrieved_docs: Annotated[list[dict], operator.add]
    answer: str
    iteration: int
    grade: str  # "sufficient" | "retry" | "fail"


class SubQuestions(BaseModel):
    questions: list[str] = Field(description="3-5 sub-questions that decompose the user query.")


class GradedAnswer(BaseModel):
    grade: str = Field(description="One of: sufficient | retry")
    rationale: str
    additional_query: str = Field(description="If retry, the new query to retrieve with. Empty if sufficient.")


llm = ChatAnthropic(model="claude-sonnet-4-5", temperature=0.2)
store = QdrantVectorStore.from_existing_collection(embedding=BGEEmbeddings(), url=os.environ.get("QDRANT_URL", "http://localhost:6333"), collection_name="ossai_docs")


def plan(state: GraphState) -> GraphState:
    out = llm.with_structured_output(SubQuestions).invoke(
        f"Decompose this question into 3-5 specific sub-questions a search engine can answer. Question: {state['question']}"
    )
    return {"sub_questions": out.questions, "iteration": 0}


def retrieve(state: GraphState) -> GraphState:
    new_docs = []
    for sq in state["sub_questions"]:
        for d in store.similarity_search(sq, k=3):
            new_docs.append({"sub_q": sq, "content": d.page_content, "source": d.metadata.get("source")})
    return {"retrieved_docs": new_docs, "iteration": state["iteration"] + 1}


def grade(state: GraphState) -> GraphState:
    context = "\n\n".join(d["content"][:400] for d in state["retrieved_docs"])
    out = llm.with_structured_output(GradedAnswer).invoke(
        f"Question: {state['question']}\nContext:\n{context}\n\nIs the context sufficient to answer fully? Reply 'sufficient' or 'retry'. If retry, propose a focused additional query."
    )
    if out.grade == "retry" and out.additional_query and state["iteration"] < 3:
        return {"grade": "retry", "sub_questions": [out.additional_query]}
    return {"grade": "sufficient"}


def answer(state: GraphState) -> GraphState:
    context = "\n\n".join(f"[{i+1}] ({d.get('sub_q')}) {d['content']}" for i, d in enumerate(state["retrieved_docs"]))
    out = llm.invoke(f"Answer ONLY from the context. Cite as [n]. If insufficient, say so.\n\nContext:\n{context}\n\nQuestion: {state['question']}")
    return {"answer": out.content}


def route_after_grade(state: GraphState) -> str:
    return "retrieve" if state.get("grade") == "retry" else "answer"


def build_graph():
    g = StateGraph(GraphState)
    g.add_node("plan", plan)
    g.add_node("retrieve", retrieve)
    g.add_node("grade", grade)
    g.add_node("answer", answer)
    g.set_entry_point("plan")
    g.add_edge("plan", "retrieve")
    g.add_edge("retrieve", "grade")
    g.add_conditional_edges("grade", route_after_grade, {"retrieve": "retrieve", "answer": "answer"})
    g.add_edge("answer", END)
    return g.compile()


if __name__ == "__main__":
    graph = build_graph()
    out = graph.invoke({"question": "What was the impact of the 2024 refund policy change on Q1 2025 cancellations?", "retrieved_docs": [], "iteration": 0})
    print(out["answer"])

